    [FunctionName("QueryReports")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        
        string tableName = req.Query["table"];
        if (string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Table parameter is required");
        }

        var queryBuilder = new StringBuilder();
        queryBuilder.Append($"SELECT * FROM {tableName} WHERE 1=1");

        foreach (var param in req.Query)
        {
            if (param.Key.ToLower() == "table" || param.Key.ToLower() == "orderby" || 
                param.Key.ToLower() == "limit" || param.Key.ToLower() == "offset")
            {
                continue;
            }

            string value = param.Value.ToString();
            if (!string.IsNullOrEmpty(value))
            {
                if (value.Contains("*") || value.Contains("%"))
                {
                    queryBuilder.Append($" AND {param.Key} LIKE '{value.Replace("*", "%")}'");
                }
                else if (value.StartsWith(">") || value.StartsWith("<") || value.StartsWith("="))
                {
                    if (value.StartsWith(">=") || value.StartsWith("<=") || value.StartsWith("<>"))
                    {
                        string op = value.Substring(0, 2);
                        string val = value.Substring(2);
                        queryBuilder.Append($" AND {param.Key} {op} '{val}'");
                    }
                    else
                    {
                        string op = value.Substring(0, 1);
                        string val = value.Substring(1);
                        queryBuilder.Append($" AND {param.Key} {op} '{val}'");
                    }
                }
                else
                {
                    queryBuilder.Append($" AND {param.Key} = '{value}'");
                }
            }
        }

        if (req.Query.ContainsKey("orderby"))
        {
            string orderBy = req.Query["orderby"];
            queryBuilder.Append($" ORDER BY {orderBy}");
        }

        if (req.Query.ContainsKey("limit"))
        {
            string limit = req.Query["limit"];
            string offset = req.Query.ContainsKey("offset") ? req.Query["offset"].ToString() : "0";
            queryBuilder.Append($" OFFSET {offset} ROWS FETCH NEXT {limit} ROWS ONLY");
        }

        string sqlQuery = queryBuilder.ToString();
        log.LogInformation($"Executing query: {sqlQuery}");

        var results = new List<Dictionary<string, object>>();

        try
        {
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (SqlCommand command = new SqlCommand(sqlQuery, connection))
                {
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return new OkObjectResult(new
            {
                query = sqlQuery,
                count = results.Count,
                data = results
            });
        }
        catch (Exception ex)
        {
            log.LogError($"Error executing query: {ex.Message}");
            return new StatusCodeResult(500);
        }
